1	export type Cell = [x: number, y: number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const toKey = ([x, y]: Cell): string => `${x},${y}`;
10	const fromKey = (key: string): Cell =>
11	  key.split(",").map(Number) as Cell;
12	
13	const isAliveNextGeneration = (neighborCount: number, isAlive: boolean): boolean =>
14	  neighborCount === 3 || (neighborCount === 2 && isAlive);
15	
16	export function nextGeneration(cells: Cell[]): Cell[] {
17	  const alive = new Set(cells.map(toKey));
18	  const neighborCounts = new Map<string, number>();
19	
20	  for (const [x, y] of cells) {
21	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
22	      const key = toKey([x + dx, y + dy]);
23	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
24	    }
25	  }
26	
27	  return Array.from(neighborCounts)
28	    .filter(([key, count]) => isAliveNextGeneration(count, alive.has(key)))
29	    .map(([key]) => fromKey(key));
30	}
