1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (0 neighbors) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent cells both die (1 neighbor each) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life stays unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("blinker oscillates from vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
21	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
23	    const result = nextGeneration(vertical);
24	    expect(result).toHaveLength(3);
25	    expect(result).toEqual(expect.arrayContaining(horizontal));
26	  });
27	  it("dead cell with exactly 3 live neighbors becomes alive (reproduction) — L-shape produces filled corner", () => {
28	    const lShape: [number, number][] = [[0, 0], [1, 0], [0, 1]];
29	    const expected: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
30	    const result = nextGeneration(lShape);
31	    expect(result).toHaveLength(4);
32	    expect(result).toEqual(expect.arrayContaining(expected));
33	  });
34	  it("live cell with 4 neighbors dies (overpopulation) — center of filled 3x3 dies", () => {
35	    const top: [number, number][] = [[0, 0], [1, 0], [2, 0]];
36	    const middle: [number, number][] = [[1, 1]];
37	    const bottom: [number, number][] = [[0, 2], [1, 2], [2, 2]];
38	    const input = [...top, ...middle, ...bottom];
39	    const result = nextGeneration(input);
40	    expect(result).not.toContainEqual([1, 1]);
41	  });
42	  it.todo("handles negative coordinates correctly — blinker centered at origin uses (-1,1) and (1,1)");
43	});
